"use client";

import { useEffect, useRef, useState } from "react";

// shadcn
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Button } from "@/components/ui/button";
import {
  Carousel,
  CarouselContent,
  CarouselItem,
  CarouselNext,
  CarouselPrevious,
  type CarouselApi,
} from "@/components/ui/carousel";

// constants
const testimonials = [
  {
    name: "Shirley Hoe",
    role: "Manager at Apple",
    avatar: "https://cdn.uiable.com/block/team1.png",
    initials: "SH",
    text: "At half-past eight the door opened, the policeman appeared and requesting them to follow him, led the way to an adjoining hall.",
  },
  {
    name: "John Doe",
    role: "Manager at Apple",
    avatar: "https://cdn.uiable.com/block/team2.png",
    initials: "JD",
    text: "At half-past eight the door opened, the policeman appeared and requesting them to follow him, led the way to an adjoining hall.",
  },
  {
    name: "Joseph William",
    role: "Manager at Apple",
    avatar: "https://cdn.uiable.com/block/team3.png",
    initials: "JW",
    text: "At half-past eight the door opened, the policeman appeared and requesting them to follow him, led the way to an adjoining hall.",
  },
  {
    name: "Jane Smith",
    role: "Manager at Apple",
    avatar: "https://cdn.uiable.com/block/team4.png",
    initials: "JS",
    text: "At half-past eight the door opened, the policeman appeared and requesting them to follow him, led the way to an adjoining hall.",
  },
];

// ------------------------------ | TESTIMONIAL 4 | ------------------------------ //

export default function Testimonial4() {
  const carouselRef = useRef<HTMLDivElement>(null);
  const [api, setApi] = useState<CarouselApi>();
  const [active, setActive] = useState(0);

  useEffect(() => {
    if (!api) return;
    const onSelect = () => {
      setActive(api.selectedScrollSnap());
    };
    api.on("select", onSelect);
    onSelect();
    return () => {
      api.off("select", onSelect);
    };
  }, [api]);

  const goTo = (idx: number) => {
    api?.scrollTo(idx);
  };

  return (
    <section className="py-20">
      <div className="container mx-auto px-6 flex flex-col items-center">
        <h2 className="text-center mb-10">Testimonials</h2>
        <Carousel
          opts={{
            align: "center",
            loop: true,
          }}
          setApi={setApi}
          className="w-full flex flex-col items-center"
          ref={carouselRef}
        >
          <div className="flex items-center gap-16 w-full md:p-24 justify-center">
            <CarouselPrevious className="static translate-y-0" />
            <CarouselContent className="w-auto">
              {testimonials.map((t) => (
                <CarouselItem key={t.name} className="basis-auto">
                  <div className="flex flex-col items-center">
                    <Avatar className="size-45.5 mb-4">
                      <AvatarImage src={t.avatar} alt={t.name} />
                      <AvatarFallback>{t.initials}</AvatarFallback>
                    </Avatar>

                    <h3 className="mb-1">{t.name}</h3>
                    <p className="text-muted-foreground mb-2">{t.role}</p>

                    <p className="text-muted-foreground max-w-sm mx-6 text-center mb-6">
                      {t.text}
                    </p>
                  </div>
                </CarouselItem>
              ))}
            </CarouselContent>
            <CarouselNext className="static translate-y-0" />
          </div>
          {/* Thumbnails */}
          <div className="flex gap-2 justify-center mt-2">
            {testimonials.map((t, i) => (
              <Button
                variant="ghost"
                key={t.name}
                aria-label={`Go to testimonial ${i + 1}`}
                onClick={() => goTo(i)}
                className={`p-0 h-auto hover:bg-transparent dark:hover:bg-transparent rounded-full transition-all ${
                  i === active
                    ? "opacity-100 scale-110"
                    : "opacity-60 hover:opacity-100"
                }`}
                type="button"
              >
                <Avatar className="size-14">
                  <AvatarImage src={t.avatar} alt={t.name} />
                  <AvatarFallback>{t.initials}</AvatarFallback>
                </Avatar>
              </Button>
            ))}
          </div>
        </Carousel>
      </div>
    </section>
  );
}
